import{_ as t,o as a,c as r,ag as o}from"./chunks/framework.CbQjVMS6.js";const p=JSON.parse('{"title":"Auto-Run Your Programs","description":"","frontmatter":{},"headers":[],"relativePath":"features/autorun.md","filePath":"features/autorun.md","lastUpdated":1774326589000}'),u={name:"features/autorun.md"};function s(i,e,n,l,h,d){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="auto-run-your-programs" tabindex="-1">Auto-Run Your Programs <a class="header-anchor" href="#auto-run-your-programs" aria-label="Permalink to &quot;Auto-Run Your Programs&quot;">​</a></h1><h2 id="using-wabbitemu" tabindex="-1">Using <a href="http://wabbitemu.org/" target="_blank" rel="noreferrer">WabbitEmu</a> <a class="header-anchor" href="#using-wabbitemu" aria-label="Permalink to &quot;Using [WabbitEmu](http://wabbitemu.org/)&quot;">​</a></h2><p>If Powerpack detects that you have <code>WabbitEmu.exe</code> running on your computer, it will attempt to send the compiled 8XP file to the emulator.</p><p>It will also press the <kbd>ENTER</kbd> key inside the emulator, which re-runs the program automatically after every compile. This allows you to iterate faster by making code changes and seeing the result more immediately.</p><p>As long are you’re running Powerpack in “<a href="/getting-started#ways-of-using-powerpack">watch mode</a>”, just hit <kbd>CTRL</kbd>+<kbd>S</kbd> in TI Connect (or your editor) and watch WabbitEmu automatically run your updated program.</p><h2 id="other-emulators" tabindex="-1">Other Emulators <a class="header-anchor" href="#other-emulators" aria-label="Permalink to &quot;Other Emulators&quot;">​</a></h2><p>Other emulators are not yet supported out-of-the box, but post a message on <a href="https://github.com/ti-powerpack/ti-powerpack.github.io/discussions/categories/ideas-suggestions" target="_blank" rel="noreferrer">Github</a> if you have one that should be supported.</p>',7)])])}const c=t(u,[["render",s]]);export{p as __pageData,c as default};
